set -e

echo "Building target curl"

SRC_DIR=deps/luvit/luv
BUILD_DIR=$SRC_DIR/cmakebuild-unix
OUT_DIR=ninjabuild-unix

LIBCURL_BUILD_OPTIONS="-DBUILD_CURL_EXE=OFF -DBUILD_SHARED_LIBS=OFF -DBUILD_STATIC_LIBS=ON -DCURL_DISABLE_INSTALL=ON"

# TBD: ENABLE_ARES, ENABLE_UNICODE (Win32 only),-DWIN32_LEAN_AND_MEAN, CURL_LTO

cmake -S $SRC_DIR -B $BUILD_DIR -G Ninja -DBUILD_MODULE=OFF -DBUILD_SHARED_LIBS=OFF -DBUILD_STATIC_LIBS=ON -DCMAKE_C_COMPILER=gcc "$LIBCURL_BUILD_OPTIONS"
cmake --build $BUILD_DIR --clean-first

cp $BUILD_DIR/libcurl_static.a $OUT_DIR
# cp $BUILD_DIR/deps/libuv/libuv.a $OUT_DIR
